DELETE FROM scenario_lines WHERE scenario_id = '00000000-0000-0000-0005-000000000001';
INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation) VALUES
  ('00000000-0000-0000-0005-000000000001', 'en', 1, 'partner', 'Delivery! I have a package here for a Mister or Miss Nguyen.', 'Giao hàng! Tôi có một bưu kiện cho anh/chị Nguyễn.'),
  ('00000000-0000-0000-0005-000000000001', 'en', 2, 'user', 'Sorry, the intercom is a bit crackly. Could you say that again, please?', 'Xin lỗi, loa bộ đàm hơi tệ. Bạn có thể nói lại được không?'),
  ('00000000-0000-0000-0005-000000000001', 'en', 3, 'partner', 'No problem! I said I have a parcel for Nguyen Minh. I''ll need a signature.', 'Không sao! Tôi nói là tôi có bưu kiện cho Nguyễn Minh. Tôi cần chữ ký.'),
  ('00000000-0000-0000-0005-000000000001', 'en', 4, 'user', 'That''s me! Please come up — third floor, apartment 3B. I''ll buzz you in now.', 'Đó là tôi! Mời lên đây — tầng 3, phòng 3B. Tôi mở cửa cho bạn ngay.'),
  ('00000000-0000-0000-0005-000000000001', 'en', 5, 'partner', 'Here''s your parcel. Could I get you to sign on this screen, please?', 'Đây là bưu kiện của bạn. Nhờ bạn ký trên màn hình này được không?'),
  ('00000000-0000-0000-0005-000000000001', 'en', 6, 'user', 'Of course. Is there anywhere in particular I need to sign?', 'Được thôi. Có chỗ nào cụ thể tôi cần ký không?'),
  ('00000000-0000-0000-0005-000000000001', 'en', 7, 'partner', 'Sign on that line there, and then could you also print your full name underneath?', 'Ký vào dòng đó, rồi bạn có thể viết tay tên đầy đủ bên dưới không?'),
  ('00000000-0000-0000-0005-000000000001', 'en', 8, 'user', 'Sorry, I didn''t catch the second part. Could you repeat that?', 'Xin lỗi, tôi không nghe rõ phần sau. Bạn có thể nhắc lại không?'),
  ('00000000-0000-0000-0005-000000000001', 'en', 9, 'partner', 'Sure! After your signature, just write your name in block letters right below it.', 'Được! Sau chữ ký, chỉ cần viết tên bằng chữ in hoa ngay bên dưới.'),
  ('00000000-0000-0000-0005-000000000001', 'en', 10, 'user', 'Got it. [signs and prints name] Is there anything else I need to do?', 'Hiểu rồi. [ký và viết tên] Còn điều gì tôi cần làm nữa không?'),
  ('00000000-0000-0000-0005-000000000001', 'en', 11, 'partner', 'That''s everything! Your tracking number is Z-X-four-eight-two-nine-one. Have a great day!', 'Xong rồi! Số theo dõi đơn hàng của bạn là ZX-48291. Chúc bạn một ngày tốt lành!'),
  ('00000000-0000-0000-0005-000000000001', 'en', 12, 'user', 'Thank you so much. You too!', 'Cảm ơn bạn rất nhiều. Bạn cũng vậy!');

