INSERT INTO scenario_lines (scenario_id, language_id, sort_order, speaker, text, translation, furigana, romaji) VALUES
  ('00000000-0000-0000-0005-000000000002', 'ja', 1, 'partner', 'ヤマト運輸です。グエン・ミン様にお荷物をお届けに参りました。', 'Đây là Yamato Unyu. Tôi đến giao hàng cho anh/chị Nguyen Minh.', 'ヤマトうんゆです。グエン・ミンさまにおにもつをおとどけにまいりました。', 'Yamato Un''yu desu. Guen Min-sama ni o-nimotsu wo o-todoke ni mairimashita.'),
  ('00000000-0000-0000-0005-000000000002', 'ja', 2, 'user', 'すみません、インターホンの音が悪くて聞き取れませんでした。もう一度おっしゃっていただけますか？', 'Xin lỗi, loa bộ đàm không rõ nên tôi không nghe được. Bạn có thể nói lại một lần nữa không?', 'すみません、インターホンのおとがわるくてききとれませんでした。もういちどおっしゃっていただけますか？', 'Sumimasen, intāhon no oto ga warukute kikitoremasen deshita. Mō ichi-do osshatte itadakemasu ka?'),
  ('00000000-0000-0000-0005-000000000002', 'ja', 3, 'partner', 'ヤマト運輸でございます。グエン・ミン様宛のお荷物をお持ちしました。', 'Đây là Yamato Unyu. Tôi mang bưu kiện cho anh/chị Nguyen Minh.', 'ヤマトうんゆでございます。グエン・ミンさまあてのおにもつをおもちしました。', 'Yamato Un''yu de gozaimasu. Guen Min-sama ate no o-nimotsu wo o-mochi shimashita.'),
  ('00000000-0000-0000-0005-000000000002', 'ja', 4, 'user', 'はい、私です。3階の3Bにいます。今、開けますね。', 'Vâng, đó là tôi. Tôi ở tầng 3 phòng 3B. Tôi mở cửa ngay nhé.', 'はい、わたしです。さんがいのさんBにいます。いま、あけますね。', 'Hai, watashi desu. San-kai no san-B ni imasu. Ima, akemasu ne.'),
  ('00000000-0000-0000-0005-000000000002', 'ja', 5, 'partner', 'こちらがお荷物です。こちらの端末にサインをいただけますか？', 'Đây là bưu kiện của bạn. Bạn có thể ký vào màn hình này không?', 'こちらがおにもつです。こちらのたんまつにサインをいただけますか？', 'Kochira ga o-nimotsu desu. Kochira no tanmatsu ni sain wo itadakemasu ka?'),
  ('00000000-0000-0000-0005-000000000002', 'ja', 6, 'user', 'はい。どこにサインすればいいですか？', 'Vâng. Tôi ký vào chỗ nào?', 'はい。どこにサインすればいいですか？', 'Hai. Doko ni sain sureba ii desu ka?'),
  ('00000000-0000-0000-0005-000000000002', 'ja', 7, 'partner', 'この枠内にサインをして、その下にお名前をご記入いただけますか？', 'Ký vào khung này, rồi viết tên vào bên dưới được không?', 'このわくないにサインをして、そのしたにおなまえをごきにゅういただけますか？', 'Kono waku-nai ni sain wo shite, sono shita ni o-namae wo go-kinyū itadakemasu ka?'),
  ('00000000-0000-0000-0005-000000000002', 'ja', 8, 'user', 'すみません、もう一度言っていただけますか？少し聞き取れなかったです。', 'Xin lỗi, bạn có thể nói lại được không? Tôi nghe không rõ lắm.', 'すみません、もういちどいっていただけますか？すこしききとれなかったです。', 'Sumimasen, mō ichi-do itte itadakemasu ka? Sukoshi kikitorenakatta desu.'),
  ('00000000-0000-0000-0005-000000000002', 'ja', 9, 'partner', 'はい、失礼しました。まずサイン欄にサインをして、それからサインの下にお名前をお書きください。', 'Vâng, xin lỗi. Trước tiên ký vào ô chữ ký, rồi viết tên ngay bên dưới chữ ký.', 'はい、しつれいしました。まずサインらんにサインをして、それからサインのしたにおなまえをおかきください。', 'Hai, shitsurei shimashita. Mazu sain-ran ni sain wo shite, sorekara sain no shita ni o-namae wo o-kaki kudasai.'),
  ('00000000-0000-0000-0005-000000000002', 'ja', 10, 'user', 'わかりました。[サイン・記入する] これでよろしいでしょうか？', 'Hiểu rồi. [ký và viết tên] Như vậy có được không?', 'わかりました。[サイン・きにゅうする] これでよろしいでしょうか？', 'Wakarimashita. [sain / kinyū suru] Kore de yoroshii deshō ka?'),
  ('00000000-0000-0000-0005-000000000002', 'ja', 11, 'partner', 'はい、ありがとうございます。お問い合わせ番号はZX-四八二九一でございます。', 'Vâng, cảm ơn bạn. Số theo dõi đơn hàng là ZX-48291.', 'はい、ありがとうございます。おといあわせばんごうはZX-しはちにきゅういちでございます。', 'Hai, arigatō gozaimasu. O-toiawase bangō wa ZX-shi-hachi-ni-kyū-ichi de gozaimasu.'),
  ('00000000-0000-0000-0005-000000000002', 'ja', 12, 'user', 'ありがとうございます。気をつけていってらっしゃいませ。', 'Cảm ơn bạn. Hãy cẩn thận trên đường nhé.', 'ありがとうございます。きをつけていってらっしゃいませ。', 'Arigatō gozaimasu. Ki wo tsukete itterasshai-mase.');
